import React, { useState } from 'react';
import axios from 'axios';

const InputForm = ({ setReport }) => {
    // 1. State to hold user input
    const [formData, setFormData] = useState({
        hours: '',
        attendance: '',
        marks: ''
    });

    // 2. Logic to send data to Python Backend
    const handleSubmit = async (e) => {
        e.preventDefault();
        try {
            // This connects to your FastAPI server running on port 8000
            const response = await axios.post('http://127.0.0.1:8000/predict', {
                hours: parseFloat(formData.hours),
                attendance: parseFloat(formData.attendance),
                marks: parseFloat(formData.marks)
            });
            
            // Send the results back up to App.js to display them
            setReport(response.data);
        } catch (error) {
            console.error("Error connecting to backend:", error);
            alert("Backend not found! Make sure your Python server is running.");
        }
    };

    // 3. The professional UI (matches your CSS)
    return (
        <div className="form-container">
            <form onSubmit={handleSubmit}>
                <div className="input-group">
                    <label>Daily Study Hours</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 5" 
                        value={formData.hours}
                        onChange={(e) => setFormData({...formData, hours: e.target.value})} 
                        required 
                    />
                </div>

                <div className="input-group">
                    <label>Attendance Percentage</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 85" 
                        value={formData.attendance}
                        onChange={(e) => setFormData({...formData, attendance: e.target.value})} 
                        required 
                    />
                </div>

                <div className="input-group">
                    <label>Previous Marks (%)</label>
                    <input 
                        type="number" 
                        placeholder="e.g. 70" 
                        value={formData.marks}
                        onChange={(e) => setFormData({...formData, marks: e.target.value})} 
                        required 
                    />
                </div>

                <button type="submit">Analyze Performance</button>
            </form>
        </div>
    );
};

export default InputForm;
